    st.error("Please set the ANTHROPIC_API_KEY environment variable.")
    st.stop()

client = anthropic.Anthropic(api_key=ANTHROPIC_API_KEY)


def summarize_paper(paper_text, model_name="claude-3-opus-20240229"):
    """
    Summarizes a paper using the Anthropic Claude API.

    Args:
        paper_text (str): The text of the paper to summarize.
        model_name (str): The name of the Claude model to use.

    Returns:
        str: The summarized text.
    """
    try:
        response = client.messages.create(
            model=model_name,
            max_tokens=1024,
            messages=[
                {
                    "role": "user",
                    "content": f"Please provide a concise summary of the following research paper:\n\n{paper_text}",
                }
            ],
        )
        return response.content[0].text if response.content else "Summary could not be generated."
    except Exception as e:
        return f"Error during summarization: {e}"


def ask_question(summary_text, question, model_name="claude-3-opus-20240229"):
    """
    Asks a question about the summarized paper using the Anthropic Claude API.

    Args:
        summary_text (str): The summarized text of the paper.
        question (str): The question to ask.
        model_name (str): The name of the Claude model to use.

    Returns:
        str: The answer to the question.
    """
    try:
        response = client.messages.create(
            model=model_name,
            max_tokens=512,
            messages=[
                {
                    "role": "user",
                    "content": f"Based on the following summary:\n\n{summary_text}\n\nAnswer the following question: {question}",
                }
            ],
        )
        return response.content[0].text if response.content else "Answer could not be generated."
    except Exception as e:
        return f"Error during question answering: {e}"


def main():
    """
    Main function to run the Streamlit application.
    """
    st.title("Paper Summarizer and Question Answering")

    paper_input_method = st.radio("Choose input method:", ("Text Input", "File Upload"))

    paper_text = ""
    if paper_input_method == "Text Input":
        paper_text = st.text_area("Enter the paper text:", height=300)
    elif paper_input_method == "File Upload":
        uploaded_file = st.file_uploader("Upload a paper (TXT or PDF)", type=["txt", "pdf"])
        if uploaded_file is not None:
            try:
                if uploaded_file.type == "text/plain":
                    paper_text = uploaded_file.read().decode("utf-8")
                elif uploaded_file.type == "application/pdf":
                    import pypdf

                    pdf_reader = pypdf.PdfReader(uploaded_file)
                    paper_text = ""
                    for page in pdf_reader.pages:
                        paper_text += page.extract_text()
                else:
                    st.error("Unsupported file type. Please upload a TXT or PDF file.")
                    st.stop()
            except Exception as e:
                st.error(f"Error reading file: {e}")
                st.stop()

    if st.button("Summarize"):
        if not paper_text:
            st.warning("Please enter or upload a paper.")
        else:
            with st.spinner("Summarizing..."):
                summary = summarize_paper(paper_text)
            st.subheader("Summary:")
            st.write(summary)

            st.session_state.summary = summary  # Store summary for question answering

    if "summary" in st.session_state and st.session_state.summary:
        st.subheader("Ask a Question about the Summary")
        question = st.text_input("Enter your question:")
        if st.button("Ask"):
            if not question:
                st.warning("Please enter a question.")
            else:
                with st.spinner("Answering..."):
                    answer = ask_question(st.session_state.summary, question)
                st.subheader("Answer:")
                st.write(answer)


if __name__ == "__main__":
    main()

